class SecureElasticsearchScriptClient:
    """
    Secure Elasticsearch client for executing scripts in aggregations.
    Implements security controls to prevent script injection and malicious code execution.
    """
    
    # Whitelist of allowed Painless script operations
    ALLOWED_OPERATIONS = {
        'doc', 'params', '_source', '_score', 'Math', 'String',
        'Integer', 'Long', 'Double', 'Float', 'Boolean',
        'return', 'if', 'else', 'for', 'while'
    }
    
    # Blacklist of dangerous operations
    DANGEROUS_PATTERNS = [
        r'Runtime\.getRuntime',
        r'ProcessBuilder',
        r'System\.exit',
        r'Class\.forName',
        r'\.invoke',
        r'\.newInstance',
        r'java\.io',
        r'java\.net',
        r'java\.lang\.reflect',
        r'__import__',
        r'exec\s*\(',
        r'eval\s*\(',
        r'compile\s*\(',
        r'\.\./',  # Path traversal
        r'file://',
        r'http://',
        r'https://',
    ]
    
    # Maximum script length
    MAX_SCRIPT_LENGTH = 1000
    
    # Approved script templates (pre-vetted scripts)
    APPROVED_TEMPLATES = {
        'sum_field': {
            'script': "doc[params.field].value",
            'params_schema': {'field': str}
        },
        'multiply_fields': {
            'script': "doc[params.field1].value * doc[params.field2].value",
            'params_schema': {'field1': str, 'field2': str}
        },
        'conditional_sum': {
            'script': "doc[params.field].value > params.threshold ? doc[params.field].value : 0",
            'params_schema': {'field': str, 'threshold': (int, float)}
        },
        'percentage_calc': {
            'script': "(doc[params.numerator].value / doc[params.denominator].value) * 100",
            'params_schema': {'numerator': str, 'denominator': str}
        }
    }
    
    def __init__(self, es_hosts: List[str], use_ssl: bool = True, verify_certs: bool = True):
        """
        Initialize secure Elasticsearch client.
        
        Args:
            es_hosts: List of Elasticsearch host URLs
            use_ssl: Whether to use SSL/TLS
            verify_certs: Whether to verify SSL certificates
        """
        self.es = Elasticsearch(
            es_hosts,
            use_ssl=use_ssl,
            verify_certs=verify_certs,
            timeout=30,
            max_retries=3,
            retry_on_timeout=True
        )
        
        # Script execution audit log
        self.audit_log = []
    
    def validate_script(self, script: str) -> tuple[bool, Optional[str]]:
        """
        Validate script for security issues.
        
        Args:
            script: The script code to validate
            
        Returns:
            Tuple of (is_valid, error_message)
        """
        if not script or not isinstance(script, str):
            return False, "Script must be a non-empty string"
        
        # Check script length
        if len(script) > self.MAX_SCRIPT_LENGTH:
            return False, f"Script exceeds maximum length of {self.MAX_SCRIPT_LENGTH} characters"
        
        # Check for dangerous patterns
        for pattern in self.DANGEROUS_PATTERNS:
            if re.search(pattern, script, re.IGNORECASE):
                return False, f"Script contains forbidden pattern: {pattern}"
        
        # Check for balanced brackets/parentheses
        if script.count('(') != script.count(')'):
            return False, "Unbalanced parentheses in script"
        
        if script.count('[') != script.count(']'):
            return False, "Unbalanced brackets in script"
        
        if script.count('{') != script.count('}'):
            return False, "Unbalanced braces in script"
        
        # Ensure script only uses Painless syntax (basic check)
        # Allow only alphanumeric, dots, brackets, operators, and whitespace
        allowed_chars = re.compile(r'^[a-zA-Z0-9_\s\.\[\]\(\)\{\}\+\-\*/\=\<\>\!\&\|\?\:,;\'\"]+$')
        if not allowed_chars.match(script):
            return False, "Script contains invalid characters"
        
        return True, None
    
    def validate_params(self, params: Dict[str, Any]) -> tuple[bool, Optional[str]]:
        """
        Validate script parameters.
        
        Args:
            params: Dictionary of parameters
            
        Returns:
            Tuple of (is_valid, error_message)
        """
        if not isinstance(params, dict):
            return False, "Parameters must be a dictionary"
        
        # Check parameter keys
        for key in params.keys():
            if not isinstance(key, str):
                return False, "Parameter keys must be strings"
            
            if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', key):
                return False, f"Invalid parameter name: {key}"
        
        # Check parameter values (only allow safe types)
        allowed_types = (str, int, float, bool, type(None))
        for key, value in params.items():
            if not isinstance(value, allowed_types):
                return False, f"Parameter '{key}' has invalid type: {type(value)}"
            
            # Additional validation for strings
            if isinstance(value, str):
                if len(value) > 500:
                    return False, f"Parameter '{key}' string value too long"
                
                # Check for field name injection
                if not re.match(r'^[a-zA-Z0-9_\.]+$', value):
                    return False, f"Parameter '{key}' contains invalid characters"
        
        return True, None
    
    def get_script_hash(self, script: str, params: Dict[str, Any]) -> str:
        """Generate hash for script and params for auditing."""
        content = f"{script}:{json.dumps(params, sort_keys=True)}"
        return hashlib.sha256(content.encode()).hexdigest()
    
    def execute_template_script(self, template_name: str, params: Dict[str, Any], 
                                index: str, agg_name: str = "result") -> Dict[str, Any]:
        """
        Execute a pre-approved script template.
        
        Args:
            template_name: Name of the approved template
            params: Parameters for the template
            index: Elasticsearch index to query
            agg_name: Name for the aggregation
            
        Returns:
            Aggregation results
        """
        if template_name not in self.APPROVED_TEMPLATES:
            raise ValueError(f"Unknown template: {template_name}")
        
        template = self.APPROVED_TEMPLATES[template_name]
        
        # Validate params against schema
        schema = template['params_schema']
        for param_name, param_type in schema.items():
            if param_name not in params:
                raise ValueError(f"Missing required parameter: {param_name}")
            
            if not isinstance(params[param_name], param_type):
                raise ValueError(f"Parameter '{param_name}' must be of type {param_type}")
        
        # Validate params
        is_valid, error = self.validate_params(params)
        if not is_valid:
            raise ValueError(f"Invalid parameters: {error}")
        
        script = template['script']
        
        return self._execute_aggregation(script, params, index, agg_name, template_name)
    
    def execute_custom_script(self, script: str, params: Dict[str, Any], 
                             index: str, agg_name: str = "result",
                             require_approval: bool = True) -> Dict[str, Any]:
        """
        Execute a custom script with strict validation.
        
        Args:
            script: The Painless script code
            params: Parameters for the script
            index: Elasticsearch index to query
            agg_name: Name for the aggregation
            require_approval: Whether to require manual approval (should be True in production)
            
        Returns:
            Aggregation results
        """
        # Validate script
        is_valid, error = self.validate_script(script)
        if not is_valid:
            raise ValueError(f"Invalid script: {error}")
        
        # Validate params
        is_valid, error = self.validate_params(params)
        if not is_valid:
            raise ValueError(f"Invalid parameters: {error}")
        
        if require_approval:
            raise PermissionError(
                "Custom scripts require manual approval. "
                "Please use approved templates or contact administrator."
            )
        
        return self._execute_aggregation(script, params, index, agg_name, "custom")
    
    def _execute_aggregation(self, script: str, params: Dict[str, Any], 
                            index: str, agg_name: str, script_type: str) -> Dict[str, Any]:
        """
        Internal method to execute aggregation with script.
        
        Args:
            script: The script code
            params: Script parameters
            index: Elasticsearch index
            agg_name: Aggregation name
            script_type: Type of script (template name or 'custom')
            
        Returns:
            Aggregation results
        """
        # Create audit log entry
        script_hash = self.get_script_hash(script, params)
        audit_entry = {
            'script_hash': script_hash,
            'script_type': script_type,
            'index': index,
            'timestamp': None  # Would use datetime in real implementation
        }
        self.audit_log.append(audit_entry)
        
        # Build aggregation query with stored script for better security
        query = {
            "size": 0,
            "aggs": {
                agg_name: {
                    "sum": {
                        "script": {
                            "source": script,
                            "params": params,
                            "lang": "painless"
                        }
                    }
                }
            }
        }
        
        try:
            response = self.es.search(index=index, body=query)
            return response['aggregations']
        except Exception as e:
            raise RuntimeError(f"Script execution failed: {str(e)}")
    
    def list_approved_templates(self) -> Dict[str, Dict[str, Any]]:
        """Return list of approved script templates."""
        return {
            name: {
                'script': template['script'],
                'required_params': list(template['params_schema'].keys())
            }
            for name, template in self.APPROVED_TEMPLATES.items()
        }
    
    def get_audit_log(self) -> List[Dict[str, Any]]:
        """Return audit log of script executions."""
        return self.audit_log.copy()


